import React, { useState, useEffect } from 'react';
import api from '../utils/api';

interface Lead {
  id: string;
  nom: string;
  email?: string;
}

interface SendForm {
  leadId: string;
  canal: string;
  templateKey: string;
  customMessage: string;
  useAI: boolean;
}

interface SendResult {
  success: boolean;
  message: string;
}

const CANALS: { key: string; label: string; icon: React.ReactElement; description: string }[] = [
  {
    key: 'EMAIL',
    label: 'Email',
    description: 'Boîte de réception',
    icon: (
      <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.75" strokeLinecap="round" strokeLinejoin="round">
        <path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z" />
        <polyline points="22,6 12,13 2,6" />
      </svg>
    ),
  },
  {
    key: 'LINKEDIN',
    label: 'LinkedIn',
    description: 'Réseau pro',
    icon: (
      <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.75" strokeLinecap="round" strokeLinejoin="round">
        <path d="M16 8a6 6 0 0 1 6 6v7h-4v-7a2 2 0 0 0-2-2 2 2 0 0 0-2 2v7h-4v-7a6 6 0 0 1 6-6z" />
        <rect x="2" y="9" width="4" height="12" />
        <circle cx="4" cy="4" r="2" />
      </svg>
    ),
  },
  {
    key: 'WHATSAPP',
    label: 'WhatsApp',
    description: 'Messagerie mobile',
    icon: (
      <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.75" strokeLinecap="round" strokeLinejoin="round">
        <path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z" />
      </svg>
    ),
  },
  {
    key: 'SMS',
    label: 'SMS',
    description: 'Message texte',
    icon: (
      <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.75" strokeLinecap="round" strokeLinejoin="round">
        <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
      </svg>
    ),
  },
];

const TEMPLATES: { key: string; label: string; description: string }[] = [
  { key: 'cold_email', label: 'Cold Email', description: 'Premier contact à froid' },
  { key: 'followup_j3', label: 'Follow-up J+3', description: 'Relance après 3 jours' },
  { key: 'followup_j7', label: 'Follow-up J+7', description: 'Relance après 7 jours' },
  { key: 'linkedin_connect', label: 'LinkedIn Connect', description: 'Invitation LinkedIn' },
  { key: 'sms', label: 'SMS Court', description: 'Message SMS concis' },
];

function AIIcon(): React.ReactElement {
  return (
    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.75" strokeLinecap="round" strokeLinejoin="round">
      <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z" />
    </svg>
  );
}

function SendIcon(): React.ReactElement {
  return (
    <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <line x1="22" y1="2" x2="11" y2="13" />
      <polygon points="22 2 15 22 11 13 2 9 22 2" />
    </svg>
  );
}

interface ToggleProps {
  checked: boolean;
  onChange: (v: boolean) => void;
  label: string;
}

function Toggle({ checked, onChange, label }: ToggleProps): React.ReactElement {
  return (
    <button
      type="button"
      onClick={() => onChange(!checked)}
      className={`relative flex items-center gap-3 w-full px-4 py-3 rounded-xl border transition-colors ${
        checked
          ? 'border-indigo-500/40 bg-indigo-600/10'
          : 'border-zinc-800 bg-zinc-900 hover:border-zinc-700'
      }`}
    >
      <div className={`relative flex-shrink-0 w-9 h-5 rounded-full transition-colors ${checked ? 'bg-indigo-600' : 'bg-zinc-700'}`}>
        <span
          className={`absolute top-0.5 left-0.5 w-4 h-4 rounded-full bg-white shadow-sm transition-transform ${
            checked ? 'translate-x-4' : 'translate-x-0'
          }`}
        />
      </div>
      <div className="flex items-center gap-2 text-left">
        <span className={`text-xs font-medium ${checked ? 'text-indigo-300' : 'text-zinc-400'}`}>
          <AIIcon />
        </span>
        <span className={`text-xs font-medium ${checked ? 'text-indigo-300' : 'text-zinc-300'}`}>{label}</span>
      </div>
    </button>
  );
}

export default function SendPage(): React.ReactElement {
  const [leads, setLeads] = useState<Lead[]>([]);
  const [form, setForm] = useState<SendForm>({
    leadId: '',
    canal: 'EMAIL',
    templateKey: '',
    customMessage: '',
    useAI: false,
  });
  const [result, setResult] = useState<SendResult | null>(null);
  const [loading, setLoading] = useState<boolean>(false);

  useEffect(() => {
    api.get('/leads', { params: { limit: 100 } }).then(({ data }) => setLeads(data.leads));
  }, []);

  const send = async (): Promise<void> => {
    if (!form.leadId) return alert('Sélectionnez un lead');
    setLoading(true);
    setResult(null);
    try {
      await api.post('/send', form);
      setResult({ success: true, message: 'Message envoyé avec succès !' });
    } catch (err: any) {
      setResult({ success: false, message: err.response?.data?.error || err.message });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-6">
      <div className="mb-6">
        <h1 className="text-base font-semibold text-zinc-100">Envoi de message</h1>
        <p className="text-xs text-zinc-500 mt-1">Sélectionnez un lead, un canal et un template pour envoyer</p>
      </div>

      <div className="max-w-2xl space-y-5">
        {/* Lead selector */}
        <div className="bg-zinc-900 rounded-xl border border-zinc-800 p-5">
          <h2 className="text-[10px] font-semibold text-zinc-500 uppercase tracking-wider mb-3">
            Destinataire
          </h2>
          <select
            className="w-full bg-zinc-950 border border-zinc-800 rounded-lg px-3 py-2.5 text-xs text-zinc-200 focus:outline-none focus:border-zinc-600 transition-colors appearance-none"
            value={form.leadId}
            onChange={(e) => setForm({ ...form, leadId: e.target.value })}
          >
            <option value="" className="bg-zinc-900 text-zinc-500">Sélectionner un lead...</option>
            {leads.map((l) => (
              <option key={l.id} value={l.id} className="bg-zinc-900 text-zinc-200">
                {l.nom} {l.email ? `— ${l.email}` : "— pas d'email"}
              </option>
            ))}
          </select>
        </div>

        {/* Canal selector */}
        <div className="bg-zinc-900 rounded-xl border border-zinc-800 p-5">
          <h2 className="text-[10px] font-semibold text-zinc-500 uppercase tracking-wider mb-3">
            Canal d'envoi
          </h2>
          <div className="grid grid-cols-4 gap-2.5">
            {CANALS.map((c) => (
              <button
                key={c.key}
                onClick={() => setForm({ ...form, canal: c.key })}
                className={`flex flex-col items-center gap-2 p-4 rounded-xl border transition-colors ${
                  form.canal === c.key
                    ? 'border-indigo-500/50 bg-indigo-600/10 text-indigo-300'
                    : 'border-zinc-800 bg-zinc-950 text-zinc-500 hover:border-zinc-700 hover:text-zinc-300'
                }`}
              >
                <span>{c.icon}</span>
                <span className="text-xs font-medium">{c.label}</span>
                <span className="text-[10px] text-zinc-600">{c.description}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Template selector */}
        <div className="bg-zinc-900 rounded-xl border border-zinc-800 p-5">
          <h2 className="text-[10px] font-semibold text-zinc-500 uppercase tracking-wider mb-3">
            Template
          </h2>
          <div className="space-y-1.5">
            <button
              onClick={() => setForm({ ...form, templateKey: '' })}
              className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg border text-left transition-colors ${
                form.templateKey === ''
                  ? 'border-indigo-500/40 bg-indigo-600/10'
                  : 'border-zinc-800 hover:border-zinc-700'
              }`}
              disabled={form.useAI}
            >
              <span className={`w-1.5 h-1.5 rounded-full flex-shrink-0 ${form.templateKey === '' ? 'bg-indigo-400' : 'bg-zinc-700'}`} />
              <div>
                <p className={`text-xs font-medium ${form.templateKey === '' ? 'text-indigo-300' : 'text-zinc-400'}`}>Aucun template</p>
                <p className="text-[10px] text-zinc-600">Message personnalisé uniquement</p>
              </div>
            </button>
            {TEMPLATES.map((t) => (
              <button
                key={t.key}
                onClick={() => setForm({ ...form, templateKey: t.key })}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg border text-left transition-colors ${
                  form.templateKey === t.key
                    ? 'border-indigo-500/40 bg-indigo-600/10'
                    : 'border-zinc-800 hover:border-zinc-700'
                }`}
                disabled={form.useAI}
              >
                <span className={`w-1.5 h-1.5 rounded-full flex-shrink-0 ${form.templateKey === t.key ? 'bg-indigo-400' : 'bg-zinc-700'}`} />
                <div>
                  <p className={`text-xs font-medium ${form.templateKey === t.key ? 'text-indigo-300' : 'text-zinc-300'}`}>{t.label}</p>
                  <p className="text-[10px] text-zinc-600">{t.description}</p>
                </div>
              </button>
            ))}
          </div>
        </div>

        {/* Custom message */}
        <div className="bg-zinc-900 rounded-xl border border-zinc-800 p-5">
          <h2 className="text-[10px] font-semibold text-zinc-500 uppercase tracking-wider mb-3">
            Message personnalisé
          </h2>
          <textarea
            className="w-full bg-zinc-950 border border-zinc-800 rounded-lg px-3 py-2.5 text-xs text-zinc-200 placeholder-zinc-700 focus:outline-none focus:border-zinc-600 h-28 resize-none transition-colors disabled:opacity-40"
            placeholder="Écrivez votre message ici... (optionnel si template sélectionné)"
            value={form.customMessage}
            onChange={(e) => setForm({ ...form, customMessage: e.target.value })}
            disabled={form.useAI}
          />
        </div>

        {/* AI toggle */}
        <Toggle
          checked={form.useAI}
          onChange={(v) => setForm({ ...form, useAI: v })}
          label="Générer le message avec IA (OpenAI)"
        />

        {/* Result */}
        {result && (
          <div
            className={`flex items-start gap-3 p-4 rounded-xl border text-xs ${
              result.success
                ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400'
                : 'bg-red-500/10 border-red-500/30 text-red-400'
            }`}
          >
            {result.success ? (
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="mt-0.5 flex-shrink-0">
                <polyline points="20 6 9 17 4 12" />
              </svg>
            ) : (
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="mt-0.5 flex-shrink-0">
                <circle cx="12" cy="12" r="10" />
                <line x1="12" y1="8" x2="12" y2="12" />
                <line x1="12" y1="16" x2="12.01" y2="16" />
              </svg>
            )}
            {result.message}
          </div>
        )}

        {/* Send button */}
        <button
          onClick={send}
          disabled={loading || !form.leadId}
          className="w-full flex items-center justify-center gap-2 py-3.5 bg-indigo-600 hover:bg-indigo-500 disabled:bg-zinc-800 disabled:text-zinc-600 disabled:cursor-not-allowed text-white text-sm font-medium rounded-xl transition-colors"
        >
          {loading ? (
            <>
              <svg className="animate-spin w-4 h-4" viewBox="0 0 24 24" fill="none">
                <circle cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="2" strokeDasharray="40" strokeDashoffset="10" />
              </svg>
              Envoi en cours...
            </>
          ) : (
            <>
              <SendIcon />
              Envoyer le message
            </>
          )}
        </button>
      </div>
    </div>
  );
}
